你是一个技术专家，请根据以下上下文回答问题。

问题：${question}

上下文：
${aggregatedContext}

请给出准确、详细的回答。
`;

  const answer = await llm.generate(prompt);
  return answer;
}

function aggregateContext(docs) {
  // 去重
  const uniqueDocs = docs.filter((doc, index, self) =>
    index === self.findIndex(d => d.content === doc.content)
  );

  // 压缩：提取关键信息
  const compressed = uniqueDocs.map(doc => {
    // 这里可以添加更复杂的压缩逻辑
    return doc.content;
  });

  return compressed.join('\n\n');
}

module.exports = { optimizedRAG };</code></pre><h3>Step 6: 在 OpenClaw 中使用</h3><pre><code># OpenClaw Skill: 优化后的 RAG 问答系统

